import React from 'react';
import { Card, CardContent, CardHeader, CardTitle } from '@/components/ui/card';
import { MoreVertical, Users, TrendingUp, UserPlus, Activity, BookOpen } from 'lucide-react';
import {
  DropdownMenu,
  DropdownMenuContent,
  DropdownMenuGroup,
  DropdownMenuItem,
  DropdownMenuTrigger,
} from '@/components/ui/dropdown-menu';
import { Button } from '@/components/ui/button';

// Market trends data
const trendsData = [
  {
    id: 1,
    title: 'Content Creation',
    description: 'Video, Blog, Podcast',
    value: '+1.2k',
    icon: BookOpen,
  },
  {
    id: 2,
    title: 'Digital Marketing',
    description: 'SEO, SEM, Social Ads',
    value: '+890',
    icon: TrendingUp,
  },
  {
    id: 3,
    title: 'Growth Analytics',
    description: 'Metrics, KPIs, Reports',
    value: '+650',
    icon: Activity,
  },
  {
    id: 4,
    title: 'Community Building',
    description: 'Forums, Groups, Events',
    value: '+420',
    icon: Users,
  },
  {
    id: 5,
    title: 'User Acquisition',
    description: 'Onboarding, Referrals',
    value: '+380',
    icon: UserPlus,
  },
];

const Widget2: React.FC = () => {
  return (
    <div className="px-4 sm:px-6 lg:px-8">
        <Card className="w-full max-w-md mx-auto my-6 py-6">
        <CardHeader className="flex flex-row items-start justify-between space-y-0 pb-4 px-6">
            <div>
            <CardTitle className="text-lg font-semibold">
                Market Trends
            </CardTitle>
            <p className="text-sm text-muted-foreground mt-1">
                Growth opportunities
            </p>
            </div>
            <DropdownMenu>
            <DropdownMenuTrigger asChild>
                <Button variant="ghost" className="size-8 p-0 cursor-pointer">
                <MoreVertical />
                </Button>
            </DropdownMenuTrigger>
            <DropdownMenuContent align="end">
                <DropdownMenuGroup>
                <DropdownMenuItem className="cursor-pointer">View details</DropdownMenuItem>
                <DropdownMenuItem className="cursor-pointer">Export data</DropdownMenuItem>
                <DropdownMenuItem className="cursor-pointer">Settings</DropdownMenuItem>
                </DropdownMenuGroup>
            </DropdownMenuContent>
            </DropdownMenu>
        </CardHeader>

        <CardContent className="flex flex-col gap-7 px-6">
            {trendsData.map((trend) => {
            const IconComponent = trend.icon;
            return (
                <div key={trend.id} className="flex items-center justify-between">
                <div className="flex items-center gap-3">
                    <div className='flex size-10 items-center justify-center rounded-lg bg-primary/10'>
                    <IconComponent className='size-5 text-primary' />
                    </div>
                    <div>
                    <p className="text-sm font-medium text-foreground">{trend.title}</p>
                    <p className="text-sm text-muted-foreground">{trend.description}</p>
                    </div>
                </div>
                <div className="text-right">
                    <p className="text-sm font-semibold text-foreground">{trend.value}</p>
                </div>
                </div>
            );
            })}
        </CardContent>
        </Card>
    </div>
  );
};

export default Widget2;
